#include<bits/stdc++.h>
using namespace std;
int a[100005];
priority_queue<int>q1;//大 
priority_queue<int,vector<int>,greater<int>>q2;//小 
int main()
{
	int n;
	cin>>n;
	cin>>a[1];
	q1.push(a[1]);
	cout<<a[1]<<endl;
	for(int i=2;i<=n;i++){
		cin>>a[i];
		if(a[i]>q1.top()){
			q2.push(a[i]);
		}else q1.push(a[i]);
		while(abs((int)q1.size()-(int)q2.size())>1)
		{
			if(q1.size()>q2.size()){
				q2.push(q1.top());
				q1.pop();
			}else{
				q1.push(q2.top());
				q2.pop();
			}
		}
		if(i%2){
			if(q1.size()>q2.size()){
				cout<<q1.top()<<endl;
			}else{
				cout<<q2.top()<<endl;
			}
		}

	}

}
